import pytest

from your_module import memoize

def test_memoize_happy_path():
    calls = {"count": 0}

    @memoize
    def add(a, b):
        calls["count"] += 1
        return a + b

    # First call computes result
    assert add(2, 3) == 5
    assert calls["count"] == 1

    # Second call with same args returns cached result
    assert add(2, 3) == 5
    assert calls["count"] == 1  # no new calls

    # Different args produce new computation
    assert add(3, 4) == 7
    assert calls["count"] == 2


def test_memoize_with_single_argument():
    calls = {"count": 0}

    @memoize
    def square(x):
        calls["count"] += 1
        return x * x

    assert square(4) == 16
    assert square(4) == 16
    assert calls["count"] == 1  # cached


def test_memoize_with_no_arguments():
    calls = {"count": 0}

    @memoize
    def get_value():
        calls["count"] += 1
        return 10

    # Same result always
    assert get_value() == 10
    assert get_value() == 10
    assert calls["count"] == 1  # cached


def test_memoize_edge_case_mutable_argument():
    @memoize
    def identity(x):
        return x

    # Mutable args should raise TypeError because list is unhashable
    with pytest.raises(TypeError):
        identity([1, 2, 3])


def test_memoize_function_raises_error_not_cached():
    calls = {"count": 0}

    @memoize
    def fail_on_negative(x):
        calls["count"] += 1
        if x < 0:
            raise ValueError("negative not allowed")
        return x

    # First call raises error
    with pytest.raises(ValueError):
        fail_on_negative(-1)
    assert calls["count"] == 1

    # Calling again should re‑execute and raise again, not cache the exception
    with pytest.raises(ValueError):
        fail_on_negative(-1)
    assert calls["count"] == 2


def test_memoize_distinguishes_different_argument_types():
    calls = {"count": 0}

    @memoize
    def stringify(x):
        calls["count"] += 1
        return str(x)

    assert stringify(1) == "1"
    assert stringify("1") == "1"
    assert calls["count"] == 2  # integer 1 and string "1" should be separate keys
